import{_ as t,o as r,c as o,a2 as n}from"./chunks/framework.CQMe4Urg.js";const c=JSON.parse('{"title":"术语表","description":"","frontmatter":{},"headers":[],"relativePath":"appendix/glossary.md","filePath":"appendix/glossary.md","lastUpdated":1776333512000}'),l={name:"appendix/glossary.md"};function e(i,a,s,g,h,u){return r(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="术语表" tabindex="-1">术语表 <a class="header-anchor" href="#术语表" aria-label="Permalink to &quot;术语表&quot;">​</a></h1><p>本术语表收录了 Agent 开发中常见的技术术语，按英文字母排序，提供中英对照和简明定义。</p><div class="tip custom-block"><p class="custom-block-title">使用说明</p><p>每个术语标注了<strong>首次出现的章节</strong>，方便你回到原文查看详细讲解。</p></div><hr><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><h3 id="action" tabindex="-1">Action <a class="header-anchor" href="#action" aria-label="Permalink to &quot;Action&quot;">​</a></h3><ul><li><strong>中文</strong>: 动作/行动</li><li><strong>定义</strong>: Agent 在推理后执行的具体操作，如调用工具、发送请求、返回回复。</li><li><strong>首次出现</strong>: 第 6 章 -- Agent 核心原理</li></ul><h3 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;Agent&quot;">​</a></h3><ul><li><strong>中文</strong>: 智能体/代理</li><li><strong>定义</strong>: 一个能感知环境、做出决策并执行行动的自主软件实体。在 LLM 语境中，指 LLM 驱动的、具有工具使用和自主推理能力的程序。</li><li><strong>首次出现</strong>: 第 6 章 -- Agent 核心原理</li></ul><h3 id="agent-loop" tabindex="-1">Agent Loop <a class="header-anchor" href="#agent-loop" aria-label="Permalink to &quot;Agent Loop&quot;">​</a></h3><ul><li><strong>中文</strong>: Agent 循环</li><li><strong>定义</strong>: Agent 的核心执行机制：接收输入 -&gt; LLM 推理 -&gt; 执行工具 -&gt; 反馈结果 -&gt; 再次推理，直到任务完成。</li><li><strong>首次出现</strong>: 第 6 章 -- Agent 核心原理</li></ul><h3 id="agentic-rag" tabindex="-1">Agentic RAG <a class="header-anchor" href="#agentic-rag" aria-label="Permalink to &quot;Agentic RAG&quot;">​</a></h3><ul><li><strong>中文</strong>: Agent 化 RAG</li><li><strong>定义</strong>: 将 RAG 检索过程嵌入 Agent 循环中，Agent 可以主动决定何时检索、检索什么、是否需要再次检索。</li><li><strong>首次出现</strong>: 第 7 章 -- RAG</li></ul><h3 id="alignment" tabindex="-1">Alignment <a class="header-anchor" href="#alignment" aria-label="Permalink to &quot;Alignment&quot;">​</a></h3><ul><li><strong>中文</strong>: 对齐</li><li><strong>定义</strong>: 确保 AI 系统的行为符合人类意图和价值观的技术和研究方向。</li><li><strong>首次出现</strong>: 第 13 章 -- 安全与对齐</li></ul><h3 id="attention-mechanism" tabindex="-1">Attention Mechanism <a class="header-anchor" href="#attention-mechanism" aria-label="Permalink to &quot;Attention Mechanism&quot;">​</a></h3><ul><li><strong>中文</strong>: 注意力机制</li><li><strong>定义</strong>: Transformer 的核心组件，允许模型在处理序列时关注输入的不同部分，计算各 Token 之间的相关性权重。</li><li><strong>首次出现</strong>: 第 2 章 -- LLM 基础原理</li></ul><h2 id="c" tabindex="-1">C <a class="header-anchor" href="#c" aria-label="Permalink to &quot;C&quot;">​</a></h2><h3 id="chain-of-thought-cot" tabindex="-1">Chain-of-Thought (CoT) <a class="header-anchor" href="#chain-of-thought-cot" aria-label="Permalink to &quot;Chain-of-Thought (CoT)&quot;">​</a></h3><ul><li><strong>中文</strong>: 思维链</li><li><strong>定义</strong>: 一种 Prompt 技术，引导 LLM 逐步展示推理过程，从而提升复杂任务的准确率。</li><li><strong>首次出现</strong>: 第 3 章 -- Prompt Engineering</li></ul><h3 id="chunk-chunking" tabindex="-1">Chunk / Chunking <a class="header-anchor" href="#chunk-chunking" aria-label="Permalink to &quot;Chunk / Chunking&quot;">​</a></h3><ul><li><strong>中文</strong>: 分块</li><li><strong>定义</strong>: 将长文档切分为较小文本片段的过程，是 RAG 流程的关键步骤。</li><li><strong>首次出现</strong>: 第 7 章 -- RAG</li></ul><h3 id="computer-use" tabindex="-1">Computer Use <a class="header-anchor" href="#computer-use" aria-label="Permalink to &quot;Computer Use&quot;">​</a></h3><ul><li><strong>中文</strong>: 计算机使用</li><li><strong>定义</strong>: AI Agent 通过模拟鼠标点击、键盘输入等方式直接操控计算机桌面环境的能力。</li><li><strong>首次出现</strong>: 第 16 章 -- 前沿方向</li></ul><h3 id="context-window" tabindex="-1">Context Window <a class="header-anchor" href="#context-window" aria-label="Permalink to &quot;Context Window&quot;">​</a></h3><ul><li><strong>中文</strong>: 上下文窗口</li><li><strong>定义</strong>: LLM 单次能处理的最大 Token 数量。决定了模型能&quot;看到&quot;多少输入和生成多少输出。</li><li><strong>首次出现</strong>: 第 2 章 -- LLM 基础原理</li></ul><h3 id="coordinator" tabindex="-1">Coordinator <a class="header-anchor" href="#coordinator" aria-label="Permalink to &quot;Coordinator&quot;">​</a></h3><ul><li><strong>中文</strong>: 协调器</li><li><strong>定义</strong>: Multi-Agent 系统中负责任务分配、进度跟踪和结果整合的中枢 Agent。</li><li><strong>首次出现</strong>: 第 10 章 -- Multi-Agent</li></ul><h2 id="d" tabindex="-1">D <a class="header-anchor" href="#d" aria-label="Permalink to &quot;D&quot;">​</a></h2><h3 id="decoder" tabindex="-1">Decoder <a class="header-anchor" href="#decoder" aria-label="Permalink to &quot;Decoder&quot;">​</a></h3><ul><li><strong>中文</strong>: 解码器</li><li><strong>定义</strong>: Transformer 架构的一部分，负责自回归地生成输出序列。GPT、Claude 等模型采用 Decoder-only 架构。</li><li><strong>首次出现</strong>: 第 2 章 -- LLM 基础原理</li></ul><h2 id="e" tabindex="-1">E <a class="header-anchor" href="#e" aria-label="Permalink to &quot;E&quot;">​</a></h2><h3 id="embedding" tabindex="-1">Embedding <a class="header-anchor" href="#embedding" aria-label="Permalink to &quot;Embedding&quot;">​</a></h3><ul><li><strong>中文</strong>: 嵌入/向量表示</li><li><strong>定义</strong>: 将文本（或其他数据）转换为固定维度的数值向量，使语义相似的内容在向量空间中距离相近。</li><li><strong>首次出现</strong>: 第 7 章 -- RAG</li></ul><h3 id="end-turn" tabindex="-1">End Turn <a class="header-anchor" href="#end-turn" aria-label="Permalink to &quot;End Turn&quot;">​</a></h3><ul><li><strong>中文</strong>: 结束轮次</li><li><strong>定义</strong>: Anthropic API 中的 stop_reason 值，表示模型认为已完成回答，不需要继续调用工具。</li><li><strong>首次出现</strong>: 第 5 章 -- Tool Use</li></ul><h3 id="evaluation" tabindex="-1">Evaluation <a class="header-anchor" href="#evaluation" aria-label="Permalink to &quot;Evaluation&quot;">​</a></h3><ul><li><strong>中文</strong>: 评估</li><li><strong>定义</strong>: 对 Agent 系统的输出质量、效率、安全性等维度进行量化测量的过程。</li><li><strong>首次出现</strong>: 第 11 章 -- 评估与测试</li></ul><h2 id="f" tabindex="-1">F <a class="header-anchor" href="#f" aria-label="Permalink to &quot;F&quot;">​</a></h2><h3 id="few-shot-prompting" tabindex="-1">Few-Shot Prompting <a class="header-anchor" href="#few-shot-prompting" aria-label="Permalink to &quot;Few-Shot Prompting&quot;">​</a></h3><ul><li><strong>中文</strong>: 少样本提示</li><li><strong>定义</strong>: 在 Prompt 中提供少量示例（通常 2-5 个），引导模型按照期望的格式和风格输出。</li><li><strong>首次出现</strong>: 第 3 章 -- Prompt Engineering</li></ul><h3 id="fine-tuning" tabindex="-1">Fine-Tuning <a class="header-anchor" href="#fine-tuning" aria-label="Permalink to &quot;Fine-Tuning&quot;">​</a></h3><ul><li><strong>中文</strong>: 微调</li><li><strong>定义</strong>: 在预训练模型的基础上，使用特定领域的数据继续训练，使模型在该领域表现更好。</li><li><strong>首次出现</strong>: 第 2 章 -- LLM 基础原理</li></ul><h3 id="function-calling" tabindex="-1">Function Calling <a class="header-anchor" href="#function-calling" aria-label="Permalink to &quot;Function Calling&quot;">​</a></h3><ul><li><strong>中文</strong>: 函数调用</li><li><strong>定义</strong>: LLM 生成结构化的函数调用请求的能力。OpenAI 术语，对应 Anthropic 的 Tool Use。</li><li><strong>首次出现</strong>: 第 5 章 -- Tool Use</li></ul><h2 id="g" tabindex="-1">G <a class="header-anchor" href="#g" aria-label="Permalink to &quot;G&quot;">​</a></h2><h3 id="grounding" tabindex="-1">Grounding <a class="header-anchor" href="#grounding" aria-label="Permalink to &quot;Grounding&quot;">​</a></h3><ul><li><strong>中文</strong>: 接地/事实锚定</li><li><strong>定义</strong>: 将 LLM 的输出与真实数据源关联，减少幻觉。RAG 是一种典型的 Grounding 技术。</li><li><strong>首次出现</strong>: 第 7 章 -- RAG</li></ul><h3 id="guardrails" tabindex="-1">Guardrails <a class="header-anchor" href="#guardrails" aria-label="Permalink to &quot;Guardrails&quot;">​</a></h3><ul><li><strong>中文</strong>: 护栏/安全边界</li><li><strong>定义</strong>: 对 Agent 输入输出进行过滤和限制的安全机制，防止有害内容生成或敏感信息泄露。</li><li><strong>首次出现</strong>: 第 13 章 -- 安全与对齐</li></ul><h2 id="h" tabindex="-1">H <a class="header-anchor" href="#h" aria-label="Permalink to &quot;H&quot;">​</a></h2><h3 id="hallucination" tabindex="-1">Hallucination <a class="header-anchor" href="#hallucination" aria-label="Permalink to &quot;Hallucination&quot;">​</a></h3><ul><li><strong>中文</strong>: 幻觉</li><li><strong>定义</strong>: LLM 生成看似合理但实际不正确或虚构的内容。是 LLM 的核心局限之一。</li><li><strong>首次出现</strong>: 第 2 章 -- LLM 基础原理</li></ul><h3 id="human-in-the-loop-hitl" tabindex="-1">Human-in-the-Loop (HITL) <a class="header-anchor" href="#human-in-the-loop-hitl" aria-label="Permalink to &quot;Human-in-the-Loop (HITL)&quot;">​</a></h3><ul><li><strong>中文</strong>: 人机协同</li><li><strong>定义</strong>: Agent 在关键决策点暂停，请求人类确认后再继续执行的设计模式。</li><li><strong>首次出现</strong>: 第 6 章 -- Agent 核心原理</li></ul><h3 id="hybrid-search" tabindex="-1">Hybrid Search <a class="header-anchor" href="#hybrid-search" aria-label="Permalink to &quot;Hybrid Search&quot;">​</a></h3><ul><li><strong>中文</strong>: 混合检索</li><li><strong>定义</strong>: 结合关键词检索（BM25）和向量语义检索的搜索策略，兼顾精确匹配和语义理解。</li><li><strong>首次出现</strong>: 第 7 章 -- RAG</li></ul><h2 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h2><h3 id="inference" tabindex="-1">Inference <a class="header-anchor" href="#inference" aria-label="Permalink to &quot;Inference&quot;">​</a></h3><ul><li><strong>中文</strong>: 推理</li><li><strong>定义</strong>: 将输入传给训练好的模型并获取输出的过程。在 Agent 语境中也指模型的&quot;思考&quot;过程。</li><li><strong>首次出现</strong>: 第 2 章 -- LLM 基础原理</li></ul><h2 id="j" tabindex="-1">J <a class="header-anchor" href="#j" aria-label="Permalink to &quot;J&quot;">​</a></h2><h3 id="json-schema" tabindex="-1">JSON Schema <a class="header-anchor" href="#json-schema" aria-label="Permalink to &quot;JSON Schema&quot;">​</a></h3><ul><li><strong>中文</strong>: JSON 模式</li><li><strong>定义</strong>: 用于描述 JSON 数据结构的声明式语言。在 Tool Use 中用于定义工具参数的格式和约束。</li><li><strong>首次出现</strong>: 第 5 章 -- Tool Use</li></ul><h2 id="k" tabindex="-1">K <a class="header-anchor" href="#k" aria-label="Permalink to &quot;K&quot;">​</a></h2><h3 id="knowledge-base" tabindex="-1">Knowledge Base <a class="header-anchor" href="#knowledge-base" aria-label="Permalink to &quot;Knowledge Base&quot;">​</a></h3><ul><li><strong>中文</strong>: 知识库</li><li><strong>定义</strong>: 存储结构化或非结构化知识的数据系统，通过 RAG 技术供 Agent 检索和引用。</li><li><strong>首次出现</strong>: 第 7 章 -- RAG</li></ul><h2 id="l" tabindex="-1">L <a class="header-anchor" href="#l" aria-label="Permalink to &quot;L&quot;">​</a></h2><h3 id="langchain" tabindex="-1">LangChain <a class="header-anchor" href="#langchain" aria-label="Permalink to &quot;LangChain&quot;">​</a></h3><ul><li><strong>中文</strong>: LangChain（专有名词）</li><li><strong>定义</strong>: 最流行的 LLM 应用开发框架，提供链式调用、Agent、RAG 等标准化组件。</li><li><strong>首次出现</strong>: 第 9 章 -- Agent 框架</li></ul><h3 id="langgraph" tabindex="-1">LangGraph <a class="header-anchor" href="#langgraph" aria-label="Permalink to &quot;LangGraph&quot;">​</a></h3><ul><li><strong>中文</strong>: LangGraph（专有名词）</li><li><strong>定义</strong>: 基于图（Graph）的 Agent 编排框架，用状态机模型管理 Agent 工作流。LangChain 团队开发。</li><li><strong>首次出现</strong>: 第 9 章 -- Agent 框架</li></ul><h3 id="llm-large-language-model" tabindex="-1">LLM (Large Language Model) <a class="header-anchor" href="#llm-large-language-model" aria-label="Permalink to &quot;LLM (Large Language Model)&quot;">​</a></h3><ul><li><strong>中文</strong>: 大语言模型</li><li><strong>定义</strong>: 基于 Transformer 架构、在大规模文本数据上预训练的语言模型。如 Claude、GPT-4、Gemini。</li><li><strong>首次出现</strong>: 第 2 章 -- LLM 基础原理</li></ul><h2 id="m" tabindex="-1">M <a class="header-anchor" href="#m" aria-label="Permalink to &quot;M&quot;">​</a></h2><h3 id="mcp-model-context-protocol" tabindex="-1">MCP (Model Context Protocol) <a class="header-anchor" href="#mcp-model-context-protocol" aria-label="Permalink to &quot;MCP (Model Context Protocol)&quot;">​</a></h3><ul><li><strong>中文</strong>: 模型上下文协议</li><li><strong>定义</strong>: Anthropic 提出的开放协议标准，用于标准化 AI 模型与外部数据源和工具之间的通信。</li><li><strong>首次出现</strong>: 第 12 章 -- MCP 协议</li></ul><h3 id="memory-agent-memory" tabindex="-1">Memory (Agent Memory) <a class="header-anchor" href="#memory-agent-memory" aria-label="Permalink to &quot;Memory (Agent Memory)&quot;">​</a></h3><ul><li><strong>中文</strong>: 记忆系统</li><li><strong>定义</strong>: Agent 存储和检索历史交互信息的机制，包括短期记忆（当前对话）和长期记忆（跨会话持久化）。</li><li><strong>首次出现</strong>: 第 8 章 -- 记忆系统</li></ul><h3 id="multi-agent-system" tabindex="-1">Multi-Agent System <a class="header-anchor" href="#multi-agent-system" aria-label="Permalink to &quot;Multi-Agent System&quot;">​</a></h3><ul><li><strong>中文</strong>: 多 Agent 系统</li><li><strong>定义</strong>: 由多个具有不同职责的 Agent 组成的协作系统，通过分工和通信完成复杂任务。</li><li><strong>首次出现</strong>: 第 10 章 -- Multi-Agent</li></ul><h2 id="o" tabindex="-1">O <a class="header-anchor" href="#o" aria-label="Permalink to &quot;O&quot;">​</a></h2><h3 id="observation" tabindex="-1">Observation <a class="header-anchor" href="#observation" aria-label="Permalink to &quot;Observation&quot;">​</a></h3><ul><li><strong>中文</strong>: 观察</li><li><strong>定义</strong>: ReAct 模式中，工具执行后返回的结果。Agent 根据观察结果决定下一步行动。</li><li><strong>首次出现</strong>: 第 6 章 -- Agent 核心原理</li></ul><h3 id="orchestration" tabindex="-1">Orchestration <a class="header-anchor" href="#orchestration" aria-label="Permalink to &quot;Orchestration&quot;">​</a></h3><ul><li><strong>中文</strong>: 编排</li><li><strong>定义</strong>: 协调多个 Agent 或多个步骤按照特定流程执行的过程。LangGraph 是一种编排框架。</li><li><strong>首次出现</strong>: 第 10 章 -- Multi-Agent</li></ul><h2 id="p" tabindex="-1">P <a class="header-anchor" href="#p" aria-label="Permalink to &quot;P&quot;">​</a></h2><h3 id="planning" tabindex="-1">Planning <a class="header-anchor" href="#planning" aria-label="Permalink to &quot;Planning&quot;">​</a></h3><ul><li><strong>中文</strong>: 规划</li><li><strong>定义</strong>: Agent 在执行前先制定步骤计划的设计模式。包含计划生成、执行和动态调整。</li><li><strong>首次出现</strong>: 第 6 章 -- Agent 核心原理</li></ul><h3 id="prompt-engineering" tabindex="-1">Prompt Engineering <a class="header-anchor" href="#prompt-engineering" aria-label="Permalink to &quot;Prompt Engineering&quot;">​</a></h3><ul><li><strong>中文</strong>: 提示工程</li><li><strong>定义</strong>: 设计和优化输入给 LLM 的提示文本的技术，以获取更好的输出质量。</li><li><strong>首次出现</strong>: 第 3 章 -- Prompt Engineering</li></ul><h3 id="prompt-injection" tabindex="-1">Prompt Injection <a class="header-anchor" href="#prompt-injection" aria-label="Permalink to &quot;Prompt Injection&quot;">​</a></h3><ul><li><strong>中文</strong>: 提示注入</li><li><strong>定义</strong>: 攻击者通过在输入中嵌入恶意指令来操纵 LLM 行为的安全攻击方式。</li><li><strong>首次出现</strong>: 第 13 章 -- 安全与对齐</li></ul><h2 id="r" tabindex="-1">R <a class="header-anchor" href="#r" aria-label="Permalink to &quot;R&quot;">​</a></h2><h3 id="rag-retrieval-augmented-generation" tabindex="-1">RAG (Retrieval-Augmented Generation) <a class="header-anchor" href="#rag-retrieval-augmented-generation" aria-label="Permalink to &quot;RAG (Retrieval-Augmented Generation)&quot;">​</a></h3><ul><li><strong>中文</strong>: 检索增强生成</li><li><strong>定义</strong>: 先从外部知识库检索相关信息，再将检索结果作为上下文传给 LLM 生成回答的技术。</li><li><strong>首次出现</strong>: 第 7 章 -- RAG</li></ul><h3 id="react-reasoning-acting" tabindex="-1">ReAct (Reasoning + Acting) <a class="header-anchor" href="#react-reasoning-acting" aria-label="Permalink to &quot;ReAct (Reasoning + Acting)&quot;">​</a></h3><ul><li><strong>中文</strong>: 推理与行动</li><li><strong>定义</strong>: 一种 Agent 设计模式，交替进行推理（Thought）、行动（Action）和观察（Observation）。</li><li><strong>首次出现</strong>: 第 6 章 -- Agent 核心原理</li></ul><h3 id="reflection" tabindex="-1">Reflection <a class="header-anchor" href="#reflection" aria-label="Permalink to &quot;Reflection&quot;">​</a></h3><ul><li><strong>中文</strong>: 反思/自我反思</li><li><strong>定义</strong>: Agent 对自身输出进行审视和评估，发现错误后自行修正的设计模式。</li><li><strong>首次出现</strong>: 第 6 章 -- Agent 核心原理</li></ul><h3 id="reranking" tabindex="-1">Reranking <a class="header-anchor" href="#reranking" aria-label="Permalink to &quot;Reranking&quot;">​</a></h3><ul><li><strong>中文</strong>: 重排序</li><li><strong>定义</strong>: 对初步检索结果进行二次排序，提升最终结果的相关性。常用于 RAG 流程的检索优化。</li><li><strong>首次出现</strong>: 第 7 章 -- RAG</li></ul><h3 id="resource-mcp" tabindex="-1">Resource (MCP) <a class="header-anchor" href="#resource-mcp" aria-label="Permalink to &quot;Resource (MCP)&quot;">​</a></h3><ul><li><strong>中文</strong>: 资源（MCP）</li><li><strong>定义</strong>: MCP 协议中，Server 暴露的可读数据端点。与 Tool 不同，Resource 是被动读取而非主动执行。</li><li><strong>首次出现</strong>: 第 12 章 -- MCP 协议</li></ul><h3 id="routing" tabindex="-1">Routing <a class="header-anchor" href="#routing" aria-label="Permalink to &quot;Routing&quot;">​</a></h3><ul><li><strong>中文</strong>: 路由/分发</li><li><strong>定义</strong>: 根据输入内容的特征，将请求分发到不同处理逻辑的设计模式。</li><li><strong>首次出现</strong>: 第 6 章 -- Agent 核心原理</li></ul><h2 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h2><h3 id="sandbox" tabindex="-1">Sandbox <a class="header-anchor" href="#sandbox" aria-label="Permalink to &quot;Sandbox&quot;">​</a></h3><ul><li><strong>中文</strong>: 沙箱</li><li><strong>定义</strong>: 隔离的执行环境，限制代码或工具的权限范围，防止意外或恶意操作影响宿主系统。</li><li><strong>首次出现</strong>: 第 13 章 -- 安全与对齐</li></ul><h3 id="semantic-search" tabindex="-1">Semantic Search <a class="header-anchor" href="#semantic-search" aria-label="Permalink to &quot;Semantic Search&quot;">​</a></h3><ul><li><strong>中文</strong>: 语义检索</li><li><strong>定义</strong>: 基于向量相似度的搜索方法，能理解查询的语义含义而非仅匹配关键词。</li><li><strong>首次出现</strong>: 第 7 章 -- RAG</li></ul><h3 id="state-graph" tabindex="-1">State Graph <a class="header-anchor" href="#state-graph" aria-label="Permalink to &quot;State Graph&quot;">​</a></h3><ul><li><strong>中文</strong>: 状态图</li><li><strong>定义</strong>: LangGraph 的核心概念，用有向图表示 Agent 工作流，节点是处理步骤，边是状态转移。</li><li><strong>首次出现</strong>: 第 9 章 -- Agent 框架</li></ul><h3 id="stop-reason" tabindex="-1">Stop Reason <a class="header-anchor" href="#stop-reason" aria-label="Permalink to &quot;Stop Reason&quot;">​</a></h3><ul><li><strong>中文</strong>: 停止原因</li><li><strong>定义</strong>: LLM API 返回的字段，说明模型为何停止生成。如 &quot;end_turn&quot;、&quot;tool_use&quot;、&quot;max_tokens&quot;。</li><li><strong>首次出现</strong>: 第 4 章 -- LLM API 实战</li></ul><h3 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h3><ul><li><strong>中文</strong>: 流式输出</li><li><strong>定义</strong>: LLM 逐 Token 输出结果的方式，无需等待全部生成完毕即可开始接收。</li><li><strong>首次出现</strong>: 第 4 章 -- LLM API 实战</li></ul><h3 id="system-prompt" tabindex="-1">System Prompt <a class="header-anchor" href="#system-prompt" aria-label="Permalink to &quot;System Prompt&quot;">​</a></h3><ul><li><strong>中文</strong>: 系统提示</li><li><strong>定义</strong>: 在对话开始前设置的全局指令，定义 AI 的角色、行为规则和能力边界。</li><li><strong>首次出现</strong>: 第 3 章 -- Prompt Engineering</li></ul><h2 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h2><h3 id="temperature" tabindex="-1">Temperature <a class="header-anchor" href="#temperature" aria-label="Permalink to &quot;Temperature&quot;">​</a></h3><ul><li><strong>中文</strong>: 温度</li><li><strong>定义</strong>: 控制 LLM 输出随机性的参数。温度越高，输出越多样；越低，输出越确定。</li><li><strong>首次出现</strong>: 第 4 章 -- LLM API 实战</li></ul><h3 id="token" tabindex="-1">Token <a class="header-anchor" href="#token" aria-label="Permalink to &quot;Token&quot;">​</a></h3><ul><li><strong>中文</strong>: 令牌/词元</li><li><strong>定义</strong>: LLM 处理文本的最小单位。一个 Token 大约对应 0.75 个英文单词或 0.5 个中文字。</li><li><strong>首次出现</strong>: 第 2 章 -- LLM 基础原理</li></ul><h3 id="tool-mcp" tabindex="-1">Tool (MCP) <a class="header-anchor" href="#tool-mcp" aria-label="Permalink to &quot;Tool (MCP)&quot;">​</a></h3><ul><li><strong>中文</strong>: 工具（MCP）</li><li><strong>定义</strong>: MCP 协议中，Server 暴露的可执行操作端点。模型可以决定何时调用、传什么参数。</li><li><strong>首次出现</strong>: 第 12 章 -- MCP 协议</li></ul><h3 id="tool-use" tabindex="-1">Tool Use <a class="header-anchor" href="#tool-use" aria-label="Permalink to &quot;Tool Use&quot;">​</a></h3><ul><li><strong>中文</strong>: 工具使用</li><li><strong>定义</strong>: LLM 通过结构化输出请求外部工具执行特定操作的能力。Anthropic 术语，对应 OpenAI 的 Function Calling。</li><li><strong>首次出现</strong>: 第 5 章 -- Tool Use</li></ul><h3 id="tracing" tabindex="-1">Tracing <a class="header-anchor" href="#tracing" aria-label="Permalink to &quot;Tracing&quot;">​</a></h3><ul><li><strong>中文</strong>: 追踪/链路追踪</li><li><strong>定义</strong>: 记录 Agent 执行过程中每一步操作的详细信息，用于调试、监控和评估。</li><li><strong>首次出现</strong>: 第 11 章 -- 评估与测试</li></ul><h3 id="transformer" tabindex="-1">Transformer <a class="header-anchor" href="#transformer" aria-label="Permalink to &quot;Transformer&quot;">​</a></h3><ul><li><strong>中文</strong>: Transformer</li><li><strong>定义</strong>: 2017 年 Google 提出的神经网络架构，基于自注意力机制，是所有现代 LLM 的基础。</li><li><strong>首次出现</strong>: 第 2 章 -- LLM 基础原理</li></ul><h2 id="v" tabindex="-1">V <a class="header-anchor" href="#v" aria-label="Permalink to &quot;V&quot;">​</a></h2><h3 id="vector-database" tabindex="-1">Vector Database <a class="header-anchor" href="#vector-database" aria-label="Permalink to &quot;Vector Database&quot;">​</a></h3><ul><li><strong>中文</strong>: 向量数据库</li><li><strong>定义</strong>: 专门用于存储和检索高维向量的数据库。在 RAG 中用于存储文档 Embedding 并支持相似度搜索。</li><li><strong>首次出现</strong>: 第 7 章 -- RAG</li></ul><h2 id="w" tabindex="-1">W <a class="header-anchor" href="#w" aria-label="Permalink to &quot;W&quot;">​</a></h2><h3 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><ul><li><strong>中文</strong>: 工作流</li><li><strong>定义</strong>: Agent 执行任务的预定义步骤序列。与自主决策不同，工作流是确定性的执行路径。</li><li><strong>首次出现</strong>: 第 6 章 -- Agent 核心原理</li></ul><h2 id="z" tabindex="-1">Z <a class="header-anchor" href="#z" aria-label="Permalink to &quot;Z&quot;">​</a></h2><h3 id="zero-shot-prompting" tabindex="-1">Zero-Shot Prompting <a class="header-anchor" href="#zero-shot-prompting" aria-label="Permalink to &quot;Zero-Shot Prompting&quot;">​</a></h3><ul><li><strong>中文</strong>: 零样本提示</li><li><strong>定义</strong>: 不提供任何示例，仅通过任务描述引导模型完成任务的 Prompt 技术。</li><li><strong>首次出现</strong>: 第 3 章 -- Prompt Engineering</li></ul><hr><div class="info custom-block"><p class="custom-block-title">持续更新</p><p>本术语表会随着 AI Agent 领域的发展持续更新。如果你在阅读中遇到未收录的术语，欢迎反馈。</p></div><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://docs.anthropic.com/en/docs/glossary" target="_blank" rel="noreferrer">Anthropic Glossary</a> -- Anthropic 官方术语表</li><li><a href="https://platform.openai.com/docs/overview" target="_blank" rel="noreferrer">OpenAI Documentation Glossary</a> -- OpenAI 文档中的术语说明</li><li><a href="https://paperswithcode.com/methods" target="_blank" rel="noreferrer">Papers With Code - Methods</a> -- 机器学习方法术语库</li></ul>',144)])])}const m=t(l,[["render",e]]);export{c as __pageData,m as default};
